foreach ($locale in $locales.Keys) {
  $path = "src/messages/$locale.json"
  $json = Get-Content $path -Raw | ConvertFrom-Json

  foreach ($ns in $locales[$locale].Keys) {
    $json | Add-Member -NotePropertyName $ns -NotePropertyValue ([PSCustomObject]$locales[$locale][$ns]) -Force
  }

  $json | ConvertTo-Json -Depth 10 | Set-Content $path -Encoding UTF8
  Write-Host "Updated $locale.json"
}
